import xml.etree.ElementTree as ET
from datetime import datetime
import json

def poll(last_cursor: str | None = None) -> dict:
    """
    RSS Polling Function

    参数:
        last_cursor: 上次最后处理文章的 ID (guid 或 link)

    返回:
        {
            "events": [{"title": ..., "link": ..., "published": ..., "summary": ...}, ...],
            "next_cursor": "最后处理文章的ID"
        }
    """
    # 订阅地址通过环境变量或配置传入，这里先占位
    feed_url = "{{RSS_FEED_URL}}"
    if feed_url == "{{RSS_FEED_URL}}":
        return {
            "events": [],
            "next_cursor": last_cursor or "",
            "note": "请先设置 RSS_FEED_URL"
        }

    # 取 feed
    req = urllib.request.Request(
        feed_url,
        headers={
            "User-Agent": "Forgify-RSS-Poller/1.0"
        }
    )

    try:
        with urllib.request.urlopen(req, timeout=30) as resp:
            raw = resp.read()
    except Exception as e:
        return {
            "events": [],
            "next_cursor": last_cursor or "",
            "error": f"获取 RSS 失败: {str(e)}"
        }

    # 解析 XML
    root = ET.fromstring(raw)

    # 兼容 RSS 2.0 和 Atom
    items = []

    # RSS 2.0: channel > item
    channel = root.find("channel")
    if channel is not None:
        for item in channel.findall("item"):
            guid_el = item.find("guid")
            link_el = item.find("link")
            title_el = item.find("title")
            pubdate_el = item.find("pubDate")
            desc_el = item.find("description")

            entry_id = guid_el.text if guid_el is not None else (link_el.text if link_el is not None else "")
            items.append({
                "id": entry_id,
                "title": title_el.text if title_el is not None else "",
                "link": link_el.text if link_el is not None else "",
                "published": pubdate_el.text if pubdate_el is not None else "",
                "summary": desc_el.text if desc_el is not None else ""
            })
    else:
        # Atom: entry
        for entry in root.findall("{http://www.w3.org/2005/Atom}entry"):
            id_el = entry.find("{http://www.w3.org/2005/Atom}id")
            link_el = entry.find("{http://www.w3.org/2005/Atom}link")
            title_el = entry.find("{http://www.w3.org/2005/Atom}title")
            updated_el = entry.find("{http://www.w3.org/2005/Atom}updated")
            summary_el = entry.find("{http://www.w3.org/2005/Atom}summary")

            entry_id = id_el.text if id_el is not None else (link_el.get("href") if link_el is not None else "")
            items.append({
                "id": entry_id,
                "title": title_el.text if title_el is not None else "",
                "link": link_el.get("href") if link_el is not None else "",
                "published": updated_el.text if updated_el is not None else "",
                "summary": summary_el.text if summary_el is not None else ""
            })

    if not items:
        return {
            "events": [],
            "next_cursor": last_cursor or ""
        }

    # 按时间逆序（最新的在前），找到新文章
    new_events = []
    found_cursor = False

    for entry in items:
        if last_cursor and entry["id"] == last_cursor:
            found_cursor = True
            break
        new_events.append(entry)

    # 如果没找到 cursor，可能是首次运行或 cursor 已过期 → 只返回最新一篇
    if last_cursor and not found_cursor:
        new_events = items[:1] if items else []

    # 取最新文章的 ID 作为 next_cursor
    next_cursor = items[0]["id"] if items else (last_cursor or "")

    return {
        "events": new_events,
        "next_cursor": next_cursor
    }
"}

