from datetime import datetime, timezone

def poll_rss(last_cursor=None, rss_url=None):
    """
    Poll an RSS feed and return new entries since last cursor.

    Args:
        last_cursor: The ID of the last processed entry (from previous run).
                     Empty string on first run.
        rss_url: The RSS feed URL to poll (required).

    Returns:
        dict with:
          - events: list of new entry dicts (title, link, published, summary, id)
          - next_cursor: the ID of the latest entry for next poll
    """
    if not rss_url:
        return {"events": [], "next_cursor": last_cursor or ""}

    try:
        feed = feedparser.parse(rss_url)
    except Exception as e:
        return {"events": [], "next_cursor": last_cursor or ""}

    entries = feed.entries
    if not entries:
        return {"events": [], "next_cursor": last_cursor or ""}

    # Latest entry ID (used as the new cursor regardless)
    latest_id = entries[0].get('id') or entries[0].get('link', '')

    # First run: just record the cursor, no events
    if not last_cursor:
        return {"events": [], "next_cursor": latest_id}

    # Collect entries newer than last_cursor
    events = []
    for entry in entries:
        entry_id = entry.get('id') or entry.get('link', '')
        if entry_id == last_cursor:
            # Reached last processed entry - stop
            break
        events.append({
            "title": entry.get('title', ''),
            "link": entry.get('link', ''),
            "published": entry.get('published', ''),
            "summary": entry.get('summary', ''),
            "id": entry_id
        })

    # Reverse so oldest new entry comes first
    events.reverse()

    return {"events": events, "next_cursor": latest_id}
"}

