from typing import Any

def poll(last_cursor: str | None) -> dict[str, Any]:
    # RSS feed URL — will be configurable later
    FEED_URL = "https://example.com/rss"  # TODO: replace with actual feed URL

    feed = feedparser.parse(FEED_URL)
    entries = feed.entries

    # If no cursor yet, treat all entries as new, use first entry's id as cursor
    if not last_cursor:
        if not entries:
            return {"events": [], "next_cursor": ""}
        # Use the first entry's id/guid as cursor
        first_entry = entries[0]
        cursor = first_entry.get("id") or first_entry.get("link") or hashlib.md5(first_entry.get("title", "").encode()).hexdigest()
        events = []
        for entry in entries:
            events.append({
                "title": entry.get("title"),
                "link": entry.get("link"),
                "published": entry.get("published"),
                "summary": entry.get("summary"),
            })
        return {"events": events, "next_cursor": cursor}

    # With cursor: find cutoff index, emit entries before it (newer first)
    new_events = []
    new_cursor = last_cursor
    for entry in entries:
        entry_id = entry.get("id") or entry.get("link") or hashlib.md5(entry.get("title", "").encode()).hexdigest()
        if entry_id == last_cursor:
            # Reached the last seen entry, stop
            break
        new_events.append({
            "title": entry.get("title"),
            "link": entry.get("link"),
            "published": entry.get("published"),
            "summary": entry.get("summary"),
        })
        new_cursor = entry_id

    return {"events": new_events, "next_cursor": new_cursor}
"}
